        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new AuctionPrintMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[AuctionPrintMessage](sbeTemplateId=");
            builder.Append(AuctionPrintMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(AuctionPrintMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != AuctionPrintMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(AuctionPrintMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != AuctionPrintMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(AuctionPrintMessage.BlockLength);
            builder.Append("):");

            builder.Append("FromCache=");
            builder.Append(this.FromCache);
            builder.Append('|');
            builder.Append("ContainsFlex=");
            builder.Append(this.ContainsFlex);
            builder.Append('|');
            builder.Append("ContainsHedge=");
