            var legs = this.Legs;
            if (legs.Count > 0)
            {
                var first = true;
                while (legs.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    legs.Next().BuildString(builder);
                }
            }
            builder.Append("]");
